package main

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Security: Prevent SSRF attacks by blocking private/local IPs
	if isPrivateIP(parsedURL.Hostname()) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private/local IP addresses is not allowed"})
	}

	// Security: Set timeout and context to prevent resource exhaustion
	client := &http.Client{
		Timeout: 3 * time.Second,
		// Security: Disable redirects to prevent open redirect attacks
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Security: Use context with timeout
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to create request"})
	}

	// Security: Set safe headers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	httpReq.Header.Set("Accept-Language", "en-US,en;q=0.5")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Security: Don't expose internal error details
		if strings.Contains(err.Error(), "context deadline exceeded") {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Request timeout"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Security: Limit response size to prevent memory exhaustion
	maxSize := int64(1024 * 1024) // 1MB
	body, err := io.ReadAll(io.LimitReader(resp.Body, maxSize))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Security: Check content type to ensure we're parsing HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not return HTML content"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Security: Limit title and description length to prevent DoS
	if len(title) > 200 {
		title = title[:200] + "..."
	}
	if len(description) > 500 {
		description = description[:500] + "..."
	}

	return title, description
}

// Security: Helper function to check if hostname resolves to private/local IP
func isPrivateIP(hostname string) bool {
	// Check for localhost or loopback
	if hostname == "localhost" || strings.HasPrefix(hostname, "127.") || 
	   strings.HasPrefix(hostname, "::1") || hostname == "::1" {
		return true
	}

	// Check for private network ranges
	privateRanges := []string{
		"10.", "172.16.", "172.17.", "172.18.", "172.19.", 
		"172.20.", "172.21.", "172.22.", "172.23.", "172.24.", 
		"172.25.", "172.26.", "172.27.", "172.28.", "172.29.", 
		"172.30.", "172.31.", "192.168.", "169.254.",
	}

	for _, prefix := range privateRanges {
		if strings.HasPrefix(hostname, prefix) {
			return true
		}
	}

	return false
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

