	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prevent SSRF attacks - restrict to public internet
	if isPrivateIP(parsedURL.Hostname()) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private networks is not allowed"})
	}

	// Set timeout to prevent DoS
	client := &http.Client{
		Timeout: 10 * time.Second,
	}

	// Create request with context
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set user agent
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		// Check if context was cancelled
		if ctx.Request().Context().Err() != nil {
			return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Request timeout"})
		}
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Limit response size to prevent memory exhaustion
	limitedReader := &io.LimitedReader{R: resp.Body, N: 1024 * 1024} // 1MB limit

	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Check if we hit the limit
	if limitedReader.N <= 0 {
