		})
	}

	// Parse HTML to extract title and meta description
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
		})
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body io.Reader) (string, string, error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title from <title> tag
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
		}

		// Extract description from meta tag
		if n.Type == html.ElementNode && n.Data == "meta" {
