// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest

	// Parse JSON request body
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON format",
		})
	}

	// Validate URL is provided
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context
	httpReq, err := http.NewRequestWithContext(context.Background(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Set User-Agent to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{
			Error: fmt.Sprintf("HTTP error: %s", resp.Status),
		})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to read response: %v", err),
		})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent string) (string, string) {
	var title, description string

	// Parse the HTML
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Recursive function to traverse the HTML tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Check for title tag
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
